sql.where:
d.del_flag = '0'

	AND d.park_id = #{device.parkId}
	AND d.building_id = #{device.buildingId}
	AND d.floor_no = #{device.floorNo}
	AND d.room_id = #{device.roomId}
	AND d.device_name LIKE CONCAT('%', #{device.deviceName}, '%')
	AND d.device_code LIKE CONCAT('%', #{device.deviceCode}, '%')
	AND d.device_type = #{device.deviceType}
	AND d.device_type IN ('electric', 'water')
	AND d.online_status = #{device.onlineStatus}
	AND d.enabled_status = #{device.enabledStatus}
